const BASE_SOURCE_STRINGS = Object.keys(ROWS) as Array<keyof typeof ROWS>;

export const WEBSHOP_CATEGORIES_SOURCE_STRINGS = [
  ...BASE_SOURCE_STRINGS,
  ...EXTRA_SOURCE_STRINGS,
  ...ERROR_SOURCE_STRINGS,
] as const;

type WebshopCategoriesSource =
  (typeof WEBSHOP_CATEGORIES_SOURCE_STRINGS)[number];

function createMap(
  language: LocalizedLanguage,
): Record<WebshopCategoriesSource, string> {
  const languageIndex = LOCALIZED_LANGUAGES.indexOf(language);
  if (languageIndex < 0) {
    throw new Error(`Unsupported webshop categories language ${language}.`);
  }

  const extraValues = EXTRA_ROWS[language].split("|");
  if (extraValues.length !== EXTRA_SOURCE_STRINGS.length) {
    throw new Error(
      `Invalid webshop categories extra translation row for ${language}: expected ${EXTRA_SOURCE_STRINGS.length}, received ${extraValues.length}.`,
    );
  }
  const errorValues = ERROR_ROWS[language].split("|");
  if (errorValues.length !== ERROR_SOURCE_STRINGS.length) {
    throw new Error(
      `Invalid webshop categories error translation row for ${language}: expected ${ERROR_SOURCE_STRINGS.length}, received ${errorValues.length}.`,
    );
  }

  return {
    ...Object.fromEntries(
      BASE_SOURCE_STRINGS.map((source) => {
        const row = ROWS[source];
        if (row.length !== LOCALIZED_LANGUAGES.length) {
          throw new Error(
            `Invalid webshop categories translation row for ${source}.`,
          );
        }

        return [source, row[languageIndex] ?? source];
      }),
    ),
    ...Object.fromEntries(
      EXTRA_SOURCE_STRINGS.map((source, index) => [
        source,
        extraValues[index] ?? source,
      ]),
    ),
    ...Object.fromEntries(
      ERROR_SOURCE_STRINGS.map((source, index) => [
        source,
        errorValues[index] ?? source,
      ]),
    ),
  } as Record<WebshopCategoriesSource, string>;
}

export const WEBSHOP_CATEGORIES_SOURCE_TRANSLATIONS = Object.fromEntries(
  LOCALIZED_LANGUAGES.map((language) => [language, createMap(language)]),
) as Record<LocalizedLanguage, Record<WebshopCategoriesSource, string>>;
